import React from 'react';

const Industries = () => {
  const industries = ["Healthcare", "Information Technology", "Manufacturing", "Finance", "Construction"];

  return (
    <div className="pt-24 min-h-screen bg-gray-50">
      <div className="max-w-7xl mx-auto px-4 py-16">
        <h1 className="text-4xl font-bold text-gray-900 mb-10">Industries We Serve</h1>
        <div className="grid md:grid-cols-3 gap-6">
          {industries.map((ind) => (
            <div key={ind} className="bg-white p-8 rounded-xl shadow-sm hover:shadow-md transition-shadow border-t-4 border-blue-600">
              <h3 className="text-xl font-semibold">{ind}</h3>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
};

export default Industries;
